using System;

class Program
{
    static double Calculate(double a, double b, string op)
    {
        switch (op)
        {
            case "+": return a + b;
            case "-": return a - b;
            case "*": return a * b;
            case "/":
                if (b == 0)
                {
                    Console.WriteLine("Hata: Sifira bolme!");
                    return double.NaN;
                }
                return a / b;
            default:
                Console.WriteLine("Gecersiz islem: " + op);
                return double.NaN;
        }
    }

    static void Main()
    {
        double x = 15;
        double y = 4;

        Console.WriteLine($"x = {x}, y = {y}");
        Console.WriteLine($"x + y = {Calculate(x, y, "+")}");
        Console.WriteLine($"x - y = {Calculate(x, y, "-")}");
        Console.WriteLine($"x * y = {Calculate(x, y, "*")}");
        Console.WriteLine($"x / y = {Calculate(x, y, "/")}");

        // Sifira bolme testi
        Console.WriteLine("\nSifira bolme testi:");
        Calculate(10, 0, "/");

        // Yüzde hesaplama
        double total = 250;
        double discount = 15;
        double finalPrice = total - (total * discount / 100);
        Console.WriteLine($"\n{total} TL'nin %{discount} indirimli hali: {finalPrice} TL");
    }
}
